import { Injectable, OnDestroy } from '@angular/core';
import { Subject } from 'rxjs';

declare const gtag: any;

@Injectable({
  providedIn: 'root',
})
export class AnalyticsGaGtmColivingRewriteService implements OnDestroy {
  private readonly SUFFIX_SIGNAL = '_S_U_F_F_I_X__A_N_A_L_Y_T_I_C_S__S_I_G_N_A_L_';
  private readonly unsubscribe$ = new Subject<void>();
  private enableAnalyticsRequestRewrite = false;

  constructor() {
    this.initializeAnalyticsRewrite();
  }

  public initGaGtmColiving(value: boolean): void {
    this.enableAnalyticsRequestRewrite = value;
  }

  public shouldApplyRewrite(url: string): boolean {
    return this.enableAnalyticsRequestRewrite && /google-analytics\.com/.test(url);
  }

  public gtagWithSuffix(typeParameter: string, eventName: string, data: any): void {
    gtag(typeParameter, `${eventName}${this.enableAnalyticsRequestRewrite ? this.SUFFIX_SIGNAL : ''}`, data);
  }

  public ngOnDestroy(): void {
    this.unsubscribe$.next();
    this.unsubscribe$.complete();
  }

  private initializeAnalyticsRewrite(): void {
    const replaceSuffix = (text: string): string => text.replaceAll(this.SUFFIX_SIGNAL, '');
    this.overrideSendBeacon(replaceSuffix);
    this.overrideFetch(replaceSuffix);
  }

  private overrideSendBeacon(replaceSuffix: (text: string) => string): void {
    const originalSendBeacon = navigator.sendBeacon;
    navigator.sendBeacon = (url: string, data?: any): boolean => {
      if (this.shouldApplyRewrite(url)) {
        url = replaceSuffix(url);
        if (data && typeof data === 'string') {
          const listOfPayloads = data.split('\r\n').map(replaceSuffix);
          data = listOfPayloads.join('\r\n');
        }
      }
      return originalSendBeacon.apply(navigator, [url, data]);
    };
  }

  private overrideFetch(replaceSuffix: (text: string) => string): void {
    const originalFetch = globalThis.fetch;
    globalThis.fetch = async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
      let inputUrl: string;
      if (typeof input === 'string') {
        inputUrl = input;
      } else if (input instanceof URL) {
        inputUrl = input.toString();
      } else {
        inputUrl = input.url;
      }

      if (this.shouldApplyRewrite(inputUrl)) {
        if (typeof input === 'string' || input instanceof URL) {
          input = replaceSuffix(input.toString());
        } else if (input instanceof Request) {
          input = new Request(replaceSuffix(input.url), input);
        }
        if (init?.body && typeof init.body === 'string') {
          init = { ...init, body: replaceSuffix(init.body) };
        }
      }
      return originalFetch(input, init);
    };
  }
}

import { Injectable } from '@angular/core';

import { AnalyticsEngine } from '../enums/analytics-engines.enum';
import { AnalyticsConfig, AnalyticsEngineConfig } from '../interfaces/analytics-config.interface';
import { AnalyticsEngineStrategy } from '../interfaces/analytics-engine-strategy.interfaces';
import { AnalyticsEvent } from '../interfaces/events/analytics-event.interfaces';
import { AmplitudeService } from '../strategies/amplitude.strategy';
import { GoogleAnalyticsService } from '../strategies/google-analytics.strategy';
import { GTMService } from '../strategies/gtm-analytics.strategy';
import { YandexMetricaService } from '../strategies/yandex-analytics.strategy';

@Injectable({
  providedIn: 'root',
})
export class AnalyticsService {
  private config?: AnalyticsConfig;
  private readonly engines = new Map<AnalyticsEngine, AnalyticsEngineStrategy>();

  constructor(
    private readonly googleAnalytics: GoogleAnalyticsService,
    private readonly gtm: GTMService,
    private readonly amplitude: AmplitudeService,
    private readonly yandex: YandexMetricaService
  ) {
    this.engines.set(AnalyticsEngine.GOOGLE_ANALYTICS, this.googleAnalytics);
    this.engines.set(AnalyticsEngine.GOOGLE_TAG_MANAGER, this.gtm);
    this.engines.set(AnalyticsEngine.AMPLITUDE, this.amplitude);
    this.engines.set(AnalyticsEngine.YANDEX_METRICA, this.yandex);
  }

  public setConfig(analyticsConfig: AnalyticsConfig): void {
    this.config = analyticsConfig;
  }

  public trackEvent(event: AnalyticsEvent): void {
    if (this.config) {
      const enginesToUse = this.getEnginesToUse(event);
      for (const engineConfig of enginesToUse) {
        const service = this.engines.get(engineConfig.engine);
        if (service) {
          service.trackEvent(event, engineConfig.accounts || undefined);
        } else {
          console.warn(`No service found for engine: ${engineConfig.engine}`);
        }
      }
    } else {
      console.warn('Analytics configuration is not set.');
    }
  }

  private getEnginesToUse(event: AnalyticsEvent): AnalyticsEngineConfig[] {
    let enginesToUse: AnalyticsEngineConfig[] = [...this.config!.analyticsEngines];
    const exception = this.config!.analyticsExceptions?.find((ex) => ex.eventName === event.eventName);

    if (exception) {
      const hasExcludeRule = !(exception.includeDefaultEngines ?? false);

      if (hasExcludeRule) {
        enginesToUse = exception.analyticsEngines.map(({ engine, accounts }) => ({ engine, accounts }));
      } else {
        const uniqueEngines = new Map(enginesToUse.map((e) => [e.engine, e]));
        for (const { engine, accounts } of exception.analyticsEngines) {
          if (!uniqueEngines.has(engine)) {
            uniqueEngines.set(engine, { engine, accounts });
          }
        }
        enginesToUse = Array.from(uniqueEngines.values());
      }
    }
    return enginesToUse;
  }
}

import { inject, Injectable } from '@angular/core';

import { AnalyticsEvent } from '../../interfaces/events/analytics-event.interfaces';
import { ANALYTICS_EXPECTED_KEYS_MAP, AnalyticsExpectedKeysMap } from '../../tokens/analytics-expected-keys.token';

@Injectable({ providedIn: 'root' })
export class AnalyticsStrategiesService {
  private readonly expectedKeysMap: AnalyticsExpectedKeysMap = inject(ANALYTICS_EXPECTED_KEYS_MAP);

  public normalizeEvent(event: AnalyticsEvent<string>, account?: string): Record<string, any> {
    const expectedKeys = this.getExpectedKeys(event.eventName);
    const normalizedEvent: Record<string, any> = {
      ...this.getGoogleAnalyticsSendTo(event.account, account),
      ...event.data,
    };

    for (const key of expectedKeys) {
      if (!(key in normalizedEvent)) {
        normalizedEvent[key] = null;
      }
    }
    return normalizedEvent;
  }

  private getGoogleAnalyticsSendTo(eventAccount?: string, account?: string): Record<string, string> {
    if (this.isValidGoogleAnalyticsAccount(eventAccount)) {
      return { send_to: eventAccount! };
    }
    if (this.isValidGoogleAnalyticsAccount(account)) {
      return { send_to: account! };
    }
    return {};
  }

  private getExpectedKeys(eventName: string): readonly string[] {
    return this.expectedKeysMap?.[eventName] ?? [];
  }

  private isValidGoogleAnalyticsAccount(account?: string): boolean {
    const GAREGEXP: RegExp = /^(UA-\d{6,10}-\d{1,3}|G-[A-Z0-9]{7,12})$/;
    return typeof account === 'string' && GAREGEXP.test(account);
  }
}

import { Injectable } from '@angular/core';

import { AnalyticsEngineStrategy } from '../interfaces/analytics-engine-strategy.interfaces';
import { AnalyticsEvent } from '../interfaces/events/analytics-event.interfaces';
import { AnalyticsGaGtmColivingRewriteService } from '../workdarounds/GA-GTM-coliving/analytics-ga-gtm-coliving-rewrite.service';

import { AnalyticsStrategiesService } from './services/analytics-strategies.service';

declare const gtag: Function;

@Injectable({
  providedIn: 'root',
})
export class GoogleAnalyticsService implements AnalyticsEngineStrategy {
  constructor(
    private readonly analyticsStrategiesService: AnalyticsStrategiesService,
    private readonly analyticsGaGtmColivingRewriteService: AnalyticsGaGtmColivingRewriteService
  ) {}

  public trackEvent(event: AnalyticsEvent, accounts?: string[]): void {
    if (this.isGoogleAnalyticsAvailable()) {
      if (accounts?.length) {
        for (const account of accounts) {
          this.sendEvent(event, account);
        }
      } else {
        this.sendEvent(event);
      }
    } else {
      console.warn('Google Analytics is not available.');
    }
  }

  public sendEvent(event: AnalyticsEvent, account?: string): void {
    const eventToSend = this.analyticsStrategiesService.normalizeEvent(event, account);
    console.debug('GA', event.eventName, eventToSend);
    this.analyticsGaGtmColivingRewriteService.gtagWithSuffix('event', event.eventName, eventToSend);
  }

  private isGoogleAnalyticsAvailable(): boolean {
    return typeof gtag === 'function';
  }
}

